def compute_image_embeddings(paths, batch=BATCH_IMAGES):
    all_embs = []

    for i in tqdm(range(0, len(paths), batch), desc="Image encoding"):
        batch_paths = paths[i:i+batch]
        imgs = [Image.open(p).convert("RGB") for p in batch_paths]

        inputs = processor(images=imgs, return_tensors="pt", padding=True).to(DEVICE)

        with torch.no_grad(), torch.cuda.amp.autocast(enabled=(DEVICE=="cuda")):
            feats = model.get_image_features(**inputs)
            feats = feats / feats.norm(dim=-1, keepdim=True)

        all_embs.append(feats)

    return torch.cat(all_embs, dim=0)



def compute_text_embeddings(txts, batch=BATCH_TEXT):
    all_embs = []

    for i in tqdm(range(0, len(txts), batch), desc="Text encoding"):
        chunk = txts[i:i+batch]

        inputs = processor(text=chunk, return_tensors="pt", padding=True).to(DEVICE)

        with torch.no_grad(), torch.cuda.amp.autocast(enabled=(DEVICE=="cuda")):
            feats = model.get_text_features(**inputs)
            feats = feats / feats.norm(dim=-1, keepdim=True)

        all_embs.append(feats.cpu())

    return torch.cat(all_embs, dim=0)


print("Computing image embeddings...")
image_embs = compute_image_embeddings(image_paths)

print("Embeddings ready:", image_embs.shape)


def get_rank(query):
    text, label_id = query[0]
    inputs = processor(text=text, return_tensors="pt", padding=True).to(DEVICE)
    
    with torch.no_grad(), torch.cuda.amp.autocast(enabled=(DEVICE=="cuda")):
        text_emb = model.get_text_features(**inputs)
        text_emb = text_emb / text_emb.norm(dim=-1, keepdim=True)
    
    text_emb = text_emb.to(image_embs.dtype)
    sim = text_emb @ image_embs.T  # Shape: (1, N)
    
    # Squeeze to remove batch dimension, then sort
    sim_scores = sim.squeeze(0).detach().cpu().numpy()
    inds = np.argsort(-sim_scores)  # Descending order
    rank = np.where(inds == int(label_id))[0][0] + 1

    # ------- Precision@K --------
    p1 = np.mean(rank <= 1)
    p5 = np.mean(rank <= 5)
    p10 = np.mean(rank <= 10)
    p50 = np.mean(rank <= 50)
    p100 = np.mean(rank <= 100)
    p200 = np.mean(rank <= 200)

    report_dict = {
        "Precision@1": p1,
        "Precision@5": p5,
        "Precision@10": p10,
        "Precision@50": p50,
        "Precision@100": p100,
        "Precision@200": p200,
    }
    
    return rank, report_dict


def compute_retrieval_full(a2b_sims, return_ranks=False):
    """
    a2b_sims: similarity matrix (queries x candidates)
    return_ranks: whether to also return (ranks, top1_indices)
    """

    sims = a2b_sims
    n = sims.shape[0]

    # ranks[i] = rank position of the correct match for query i (0-based)
    ranks = np.zeros(n, dtype=np.int64)
    top1 = np.zeros(n, dtype=np.int64)

    for i in range(n):
        inds = np.argsort(-sims[i])          # descending similarity
        # ranks[i] = np.where(inds == some_idx[i])[0][0] # index where GT appears
        ranks[i] = np.where(inds == i)[0][0] # index where GT appears
        top1[i] = inds[0]                    # best retrieved

    # ------- Precision@K --------
    r1 = 100.0 * np.mean(ranks < 1)
    r5 = 100.0 * np.mean(ranks < 5)
    r10 = 100.0 * np.mean(ranks < 10)
    r50 = 100.0 * np.mean(ranks < 50)

    # ------- Rank Stats -------
    medr = np.floor(np.median(ranks)) + 1  # convert to 1-based
    meanr = ranks.mean() + 1               # convert to 1-based

    # ------- Combined score -------
    sum_score = r1 + r5 + r10
    import math
    report_dict = {
        "R@1": r1,
        "R@5": r5,
        "R@10": r10,
        "R@50": r50,
        "MedR": medr,
        "MeanR": meanr,
        "Sum(R1+R5+R10)": sum_score,
        "best_20": list(np.where(ranks>20)),
        "rank": math.log(np.mean(ranks+1))
    }

    if return_ranks:
        return report_dict, (ranks, top1)

    return report_dict
